// Format angka ke Rupiah
function fmt(n) {
  return new Intl.NumberFormat('id-ID', {
    style: 'currency',
    currency: 'IDR',
    maximumFractionDigits: 0
  }).format(n);
}

function fmtDiff(val, pct) {
  if (val === null || val === undefined) return '—';
  const arrow = val >= 0 ? '↑' : '↓';
  const sign  = val >= 0 ? '+' : '';
  const pctStr = pct !== null ? ` (${sign}${pct}%)` : '';
  return `${arrow} ${sign}${fmt(Math.abs(val))}${pctStr}`;
}

const d = $input.item.json.data;
const s = d.summary;
const c = d.comparison;

const platformLines = d.platforms
  .map(p => `├ ${p.platform.padEnd(8)} : ${fmt(p.omzet)} (${p.count} order)`)
  .join('\n');

const aging = d.aging;
const agingStr = Object.entries(aging.detail || {})
  .map(([k, v]) => `├ ${k}: ${v}`)
  .join('\n');

const tgl = new Date(d.date + 'T00:00:00+07:00').toLocaleDateString('id-ID', {
  weekday: 'long', day: 'numeric', month: 'long', year: 'numeric'
});

const margin = s.omzet > 0 ? ((s.grossProfit / s.omzet) * 100).toFixed(1) : '0';

const msg = [
  `📊 *LAPORAN HARIAN ELYASR*`,
  `${tgl} — 07.00 WIB`,
  ``,
  `💰 *OMZET & PROFIT*`,
  `├ Real Omzet    : ${fmt(s.omzet)}`,
  `├ HPP Total     : ${fmt(s.hpp)}`,
  `└ Gross Profit  : ${fmt(s.grossProfit)} *(${margin}%)*`,
  ``,
  `📦 *ORDER*`,
  `├ Total Masuk   : ${s.totalOrder} order`,
  `├ Terkirim      : ${s.terkirim} order`,
  `├ Pending Kirim : ${s.perluKirim} order`,
  `└ Dibatalkan    : ${s.batal} order`,
  ``,
  `🏪 *PER PLATFORM*`,
  platformLines,
  ``,
  `⏰ *AGING BACKLOG*`,
  agingStr || `Tidak ada`,
  ``,
  `🔥 *STOK KRITIS*: ${d.stokKritis} SKU perlu restock`,
  ``,
  `📈 *VS KEMARIN*`,
  `├ Omzet  : ${fmtDiff(c.omzetDiff, c.omzetDiffPct)}`,
  `└ Order  : ${c.orderCountDiff >= 0 ? '↑' : '↓'} ${Math.abs(c.orderCountDiff)} order`,
].join('\n');

return [{ json: { message: msg } }];
